import{_ as i,o as s,c as t,al as e}from"./chunks/framework.-mVGFbqa.js";const k=JSON.parse('{"title":"🖼️ Using the icon Property","description":"","frontmatter":{},"headers":[],"relativePath":"additional/using-the-icon-property.md","filePath":"additional/using-the-icon-property.md"}'),n={name:"additional/using-the-icon-property.md"};function l(o,a,r,h,p,c){return s(),t("div",null,[...a[0]||(a[0]=[e(`<h1 id="🖼️-using-the-icon-property" tabindex="-1">🖼️ Using the icon Property <a class="header-anchor" href="#🖼️-using-the-icon-property" aria-label="Permalink to &quot;🖼️ Using the icon Property&quot;">​</a></h1><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p><strong>Available from lovelace-material-components version 1.7.0</strong></p></div><h3 id="🌟-overview" tabindex="-1">🌟 Overview <a class="header-anchor" href="#🌟-overview" aria-label="Permalink to &quot;🌟 Overview&quot;">​</a></h3><p>The <code>icon</code> property is highly flexible and supports three usage modes across multiple Google cards:</p><h2 id="🔹-available-for" tabindex="-1">🔹 <strong>Available for:</strong> <a class="header-anchor" href="#🔹-available-for" aria-label="Permalink to &quot;🔹 **Available for:**&quot;">​</a></h2><h3 id="🆓-free-version" tabindex="-1">🆓 Free Version <a class="header-anchor" href="#🆓-free-version" aria-label="Permalink to &quot;🆓 Free Version&quot;">​</a></h3><ul><li><code>material-control-card</code></li><li><code>material-button-card</code></li><li><code>material-slider-card</code></li><li><code>material-climate-card</code></li></ul><h3 id="✨-pro-ultimate-version" tabindex="-1">✨ Pro - Ultimate Version <a class="header-anchor" href="#✨-pro-ultimate-version" aria-label="Permalink to &quot;✨ Pro - Ultimate Version&quot;">​</a></h3><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p><strong>All the card has the support of this.</strong></p></div><h2 id="🔹-1-static-icon" tabindex="-1">🔹 1. Static Icon <a class="header-anchor" href="#🔹-1-static-icon" aria-label="Permalink to &quot;🔹 1. Static Icon&quot;">​</a></h2><p>You can define a fixed icon, independent of the entity state:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">custom:material-control-card</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Lamp</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">entity</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">switch.lamp</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">icon</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">mdi:lightbulb</span></span></code></pre></div><p>In this case, the icon will never change.</p><h2 id="🔹-2-dynamic-icon-with-stateobj" tabindex="-1">🔹 2. Dynamic Icon with stateObj <a class="header-anchor" href="#🔹-2-dynamic-icon-with-stateobj" aria-label="Permalink to &quot;🔹 2. Dynamic Icon with stateObj&quot;">​</a></h2><p>You can dynamically change the icon based on the entity state, using the <code>[[[ ... ]]]</code> JavaScript template syntax.</p><p>Inside the template you have access to:</p><ul><li><code>entity</code> → the full entity object</li><li><code>entity.state</code> → the current state</li><li><code>hass</code> → the global Home Assistant object (services, entities, attributes, etc.)</li></ul><h3 id="example-—-climate-control" tabindex="-1">Example — Climate Control <a class="header-anchor" href="#example-—-climate-control" aria-label="Permalink to &quot;Example — Climate Control&quot;">​</a></h3><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">custom:material-control-card</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Heating</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">entity</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">climate.heating</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">icon</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  [[[ </span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    switch (entity.state) {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      case &#39;off&#39;: return &#39;m3s:thermometer&#39;;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      case &#39;heat&#39;: return &#39;mdi:fire&#39;;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      case &#39;cool&#39;: return &#39;mdi:mode-cool&#39;;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      case &#39;dry&#39;: return &#39;mdi:cool-to-dry&#39;;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      case &#39;heat_cool&#39;: return &#39;mdi:thermostat-auto&#39;;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      case &#39;auto&#39;: return &#39;mdi:auto-download&#39;;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      default: return &#39;mdi:thermometer&#39;;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    }</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  ]]]</span></span></code></pre></div><p>👉 In this example, the icon changes automatically depending on the state (off, heat, cool, etc.).</p><h2 id="🔹-3-dynamic-icon-with-attributes" tabindex="-1">🔹 3. Dynamic Icon with Attributes <a class="header-anchor" href="#🔹-3-dynamic-icon-with-attributes" aria-label="Permalink to &quot;🔹 3. Dynamic Icon with Attributes&quot;">​</a></h2><p>You can also use entity attributes when choosing an icon:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">icon</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  [[[ </span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    return entity.attributes.battery_level &gt; 20 </span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      ? &#39;mdi:battery&#39; </span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      : &#39;mdi:battery-alert&#39;;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  ]]]</span></span></code></pre></div><h2 id="⚠️-important-notes" tabindex="-1">⚠️ Important Notes <a class="header-anchor" href="#⚠️-important-notes" aria-label="Permalink to &quot;⚠️ Important Notes&quot;">​</a></h2><ul><li>Always use proper YAML indentation. Use <code>|</code> for multiline templates.</li><li>If indentation is incorrect, you may get YAML errors like &quot;bad indentation of a mapping entry&quot;.</li><li>Always return a valid icon string (<code>mdi:...</code>, <code>m3s:...</code>, etc.).</li><li>If you want to use just <code>state</code> instead of <code>entity.state</code>, make sure the underlying TypeScript function has been updated to provide it.</li></ul><h2 id="✅-summary" tabindex="-1">✅ Summary <a class="header-anchor" href="#✅-summary" aria-label="Permalink to &quot;✅ Summary&quot;">​</a></h2><ul><li><code>icon: mdi:lamp</code> → static</li><li><code>icon: | [[[ switch(entity.state) {...} ]]]</code> → dynamic by state</li><li><code>icon: | [[[ return entity.attributes.xxx ]]]</code> → dynamic by attributes</li></ul>`,27)])])}const m=i(n,[["render",l]]);export{k as __pageData,m as default};
